// MARK: - Certificate Pin Store

/// Stores known certificate pins for critical hosts.
struct CertificatePinStore {
    /// SHA-256 hashes of the Subject Public Key Info (SPKI) for pinned hosts.
    /// In production, include at least one backup pin.
    static let pins: [String: Set<String>] = [
        "api.example.com": [
            // Primary leaf/intermediate pin (base64-encoded SHA-256 of SPKI)
            "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=",
            // Backup pin (different CA or next certificate)
            "BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB="
        ]
    ]

    static func pinnedHashes(for host: String) -> Set<String>? {
        return pins[host]
    }
}

// MARK: - Network Client

/// A secure HTTP client that enforces TLS best practices for cloud endpoints
/// while allowing plaintext HTTP only for local IoT devices.
final class SecureNetworkClient: NSObject {

    // MARK: - Endpoint Types

    enum Endpoint {
        /// Cloud API – always HTTPS, certificate pinning enforced
        case cloud(path: String)
        /// Local IoT device – HTTP allowed via NSAllowsLocalNetworking
        case localDevice(host: String, port: Int, path: String)

        var url: URL {
            switch self {
            case .cloud(let path):
                return URL(string: "https://api.example.com\(path)")!
            case .localDevice(let host, let port, let path):
                // Local devices may only support HTTP
                return URL(string: "http://\(host):\(port)\(path)")!
            }
        }

        var requiresPinning: Bool {
            switch self {
            case .cloud: return true
            case .localDevice: return false
            }
        }

        var isLocalNetwork: Bool {
            switch self {
            case .cloud: return false
            case .localDevice: return true
            }
        }
    }

    // MARK: - Error Types

    enum NetworkError: Error, CustomStringConvertible {
        case certificatePinningFailed(host: String)
        case invalidServerTrust(host: String)
        case insecureConnectionBlocked(url: URL)
        case unexpectedResponse(statusCode: Int)
        case noData
        case requestFailed(underlying: Error)

        var description: String {
            switch self {
            case .certificatePinningFailed(let host):
                return "Certificate pinning validation failed for host: \(host)"
            case .invalidServerTrust(let host):
                return "Server trust evaluation failed for host: \(host)"
            case .insecureConnectionBlocked(let url):
                return "Insecure connection blocked for non-local URL: \(url)"
            case .unexpectedResponse(let code):
                return "Unexpected HTTP status code: \(code)"
            case .noData:
                return "No data received"
            case .requestFailed(let error):
                return "Request failed: \(error.localizedDescription)"
            }
        }
    }

    // MARK: - Properties

    private lazy var cloudSession: URLSession = {
        let config = URLSessionConfiguration.default
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        return URLSession(configuration: config, delegate: self, delegateQueue: nil)
