        var request = URLRequest(url: endpoint.url)
        request.httpMethod = "POST"
        request.httpBody = body
        request.setValue(contentType, forHTTPHeaderField: "Content-Type")

        if case .cloud = endpoint {
            request.setValue("application/json", forHTTPHeaderField: "Accept")
        }

        return try await perform(request: request, endpoint: endpoint)
    }

    /// Sends a command to a local IoT device.
    func sendDeviceCommand(_ command: [String: Any], toDevice host: String, port: Int = 80) async throws -> Data {
        guard isLocalNetworkAddress(host) else {
            throw NetworkError.insecureConnectionBlocked(
