        let endpoint = Endpoint.localDevice(host: host, port: port, path: "/api/command")
        let body = try JSONSerialization.data(withJSONObject: command)
        let (data, _) = try await post(endpoint: endpoint, body: body)
        return data
    }

    /// Discovers device info from a local IoT device.
    func discoverDevice(host: String, port: Int = 80) async throws -> [String: Any] {
        guard isLocalNetworkAddress(host) else {
            throw NetworkError.insecureConnectionBlocked(
                url: URL(string: "http://\(host):\(port)")!
            )
        }

        let endpoint = Endpoint.localDevice(host: host, port: port, path: "/api/info")
        let (data, _) = try await get(endpoint: endpoint)

        guard let json = try JSONSerialization.jsonObject(with: data) as? [String: Any] else {
            throw NetworkError.noData
        }
        return json
    }

    // MARK: - Private Helpers

    private func perform(request: URLRequest, endpoint: Endpoint) async throws -> (Data, HTTPURLResponse) {
        let session = endpoint.isLocalNetwork ? localSession : cloudSession

        let (data, response): (Data, URLResponse)
        do {
            (data, response) = try await session.data(for: request)
        } catch {
            throw NetworkError.requestFailed(underlying: error)
        }

        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.noData
        }

        guard (200...299).contains(httpResponse.statusCode) else {
            throw NetworkError.unexpectedResponse(statusCode: httpResponse.statusCode)
        }

        return (data, httpResponse)
    }

    /// Validates that we never send plaintext HTTP to non-local addresses.
    private func validateEndpointSecurity(_ endpoint: Endpoint) throws {
        switch endpoint {
        case .cloud:
