    /// Checks whether a host is a local/private network address.
    /// HTTP is ONLY permitted for these addresses.
    private func isLocalNetworkAddress(_ host: String) -> Bool {
        // RFC 1918 private ranges + link-local + loopback
        let localPatterns: [(prefix: String, check: ((String) -> Bool)?)] = [
            ("192.168.", nil),
            ("10.", nil),
            ("172.", { h in
                // 172.16.0.0 – 172.31.255.255
                let parts = h.split(separator: ".")
                guard parts.count >= 2, let second = Int(parts[1]) else { return false }
                return second >= 16 && second <= 31
            }),
            ("169.254.", nil),  // Link-local
            ("127.", nil),      // Loopback
        ]

        for pattern in localPatterns {
            if host.hasPrefix(pattern.prefix) {
                if let additionalCheck = pattern.check {
                    return additionalCheck(host)
                }
                return true
            }
        }

        // Also allow .local mDNS hostnames (Bonjour)
        if host.hasSuffix(".local") {
            return true
        }

        return false
    }

    // MARK: - Certificate Pinning Helpers

    /// Extracts the SHA-256 hash of the Subject Public Key Info from a certificate.
    private func sha256HashOfSPKI(for certificate: SecCertificate) -> String? {
        guard let publicKey = SecCertificateCopyKey(certificate) else {
            return nil
        }

        var error: Unmanaged<CFError>?
        guard let publicKeyData = SecKeyCopyExternalRepresentation(publicKey, &error) as Data? else {
            return nil
        }

        let hash = SHA256.hash(data: publicKeyData)
        return Data(hash).base64EncodedString()
    }
