// MARK: - URLSessionDelegate (Certificate Pinning for Cloud)

extension SecureNetworkClient: URLSessionDelegate {

    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            // Not a server trust challenge – use default handling
            completionHandler(.performDefaultHandling, nil)
            return
        }

        let host = challenge.protectionSpace.host

        // Step 1: Perform standard TLS validation (certificate chain, expiry, hostname)
        let policy = SecPolicyCreateSSL(true, host as CFString)
        SecTrustSetPolicies(serverTrust, policy)

        var trustError: CFError?
        let trustValid = SecTrustEvaluateWithError(serverTrust, &trustError)

        guard trustValid else {
            print("[Security] TLS validation failed for \(host): \(trustError?.localizedDescription ?? "unknown")")
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }

        // Step 2: Certificate pinning for hosts that require it
        if let expectedPins = CertificatePinStore.pinnedHashes(for: host) {
            let chainLength = SecTrustGetCertificateCount(serverTrust)

            var pinMatched = false

            // Check each certificate in the chain against our pins
            if let certificateChain = SecTrustCopyCertificateChain(serverTrust) as? [SecCertificate] {
                for i in 0..<min(certificateChain.count, chainLength) {
                    let certificate = certificateChain[i]
                    if let hash = sha256HashOfSPKI(for: certificate) {
                        if expectedPins.contains(hash) {
                            pinMatched = true
                            break
                        }
                    }
                }
            }

            if pinMatched {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
            } else {
                print("[Security] Certificate pinning FAILED for \(host). No pin matched.")
                completionHandler(.cancelAuthenticationChallenge, nil)
            }
        } else {
            // No pins configured for this host – standard TLS validation passed, allow
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
        }
    }
}

